request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?prop ?val WHERE {
  {
    ?model a bboExt:Model .
    FILTER(CONTAINS(STR(?model), "6e8e145a4f51488c81c0c89e863a27fa"))
    ?model ?prop ?val .
  }
  UNION
  {
    ?model a bboExt:Model .
    ?model tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
    ?model ?prop ?val .
  }
  UNION
  {
    ?model a bboExt:Model .
    ?model tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
    ?model ?prop ?val .
  }
}
LIMIT 25
